+	logPath := filepath.Join(auditDir, files[0].Name())
+	content, err := os.ReadFile(logPath)
+	if err != nil {
+		t.Fatalf("Failed to read audit log: %v", err)
+	}
+
+	lines := splitLines(string(content))
